body.script:
promise_test(async () => {
  const link = document.getElementById('link');
  const t1 = document.getElementById('t1');
  assert_not_equals(getComputedStyle(t1).backgroundColor, "rgb(0, 255, 0)");

  await new test_driver.Actions()
      .pointerMove(0, 0, {origin: link})
      .send();
  assert_equals(getComputedStyle(t1).backgroundColor, "rgb(0, 255, 0)");
}, ":hover pseudo-class on links");
